http.createServer(async (req,res)=>{const requestUrl=new URL(req.url,'http://localhost');const pathname=requestUrl.pathname;if(req.method==='OPTIONS')return sendJson(res,200,{ok:true});if(pathname==='/assets/rose.jpg')return serveBase64Asset(res,'rose-avatar.b64','image/jpeg');if(pathname==='/assets/rose-actions.css')return servePublicAsset(res,'rose-actions.css','text/css; charset=utf-8');if(pathname==='/assets/rose-actions.js')return servePublicAsset(res,'rose-actions.js','application/javascript; charset=utf-8');if(pathname==='/assets/rose-runtime.js')return servePublicAsset(res,'rose-runtime.js','application/javascript; charset=utf-8');if(pathname==='/health')return sendJson(res,200,{ok:true,service:'hunter-foreman-demo',appBridge:Boolean(bridgeUrl),aiProvider:process.env.AI_PROVIDER||'mock'});if(req.method==='GET'&&pathname==='/api/app-bridge/status')return sendJson(res,200,getStatus());if(req.method==='GET'&&pathname==='/api/tasks')return sendJson(res,200,{tasks});if(req.method==='POST'&&pathname==='/api/reset'){tasks.length=0;dispatches.length=0;return sendJson(res,200,{ok:true,reset:true});}if(req.method==='POST'&&pathname==='/api/rose'){try{const body=await readBody(req);const response=await createRoseReply(body);return sendJson(res,200,response);}catch(error){return sendJson(res,400,{ok:false,error:'ROSE could not respond to that message.',detail:error.message});}}if(req.method==='POST'&&pathname==='/api/assistant-feedback'){await readBody(req).catch(()=>({}));return sendJson(res,202,{ok:true,recorded:true});}if(req.method==='POST'&&pathname==='/api/requests'){try{const body=await readBody(req);if(!body.message||!String(body.message).trim())return sendJson(res,422,{ok:false,error:'Request message is required'});const task=await createTaskWithProvider(body);const dispatch=await sendToExternalApp(task).catch(error=>({sent:false,reason:error.message}));task.dispatch=dispatch;task.receiverState=getReceiverState(task,dispatch);task.lifecycle=buildTaskLifecycle(task,dispatch);dispatches.unshift({taskId:task.id,receiverState:task.receiverState,...dispatch});tasks.unshift(task);return sendJson(res,201,{ok:true,task,dispatch});}catch(error){return sendJson(res,400,{ok:false,error:'Invalid request body',detail:error.message});}}if(req.method==='GET'&&pathname.startsWith('/api/dispatch/'))return sendJson(res,200,dispatches.find(item=>item.taskId===decodeURIComponent(pathname.split('/').pop()))||{sent:false,reason:'No dispatch yet'});res.writeHead(200,{'content-type':'text/html'});res.end(html);}).listen(port,()=>console.log('Hunter Foreman demo running on http://localhost:'+port));
